# src/query/rewriter.py
from src.models.gateway_client import GatewayClient

REWRITE_PROMPT = """
Rewrite the following user question to be more precise and retrieval-friendly.
Output only the rewritten question, nothing else.

User question: {query}
Rewritten:"""

async def rewrite_query(query: str, client: GatewayClient) -> str:
    """Rewrite query to improve retrieval recall. Returns original on failure."""
    try:
        result = await client.complete({
            "model": "gpt-4o-mini",  # cheap model sufficient for rewriting
            "messages": [
                {"role": "user", "content": REWRITE_PROMPT.format(query=query)}
            ],
            "max_tokens": 200,
            "temperature": 0.0,
        })
        rewritten = result.content.strip()
        return rewritten if rewritten else query
    except Exception:
        return query   # degrade gracefully; never fail retrieval on rewrite error
